sql:
SELECT AVG(ei.income_per_capita) AS average_income_per_capita
FROM economic_indicators ei
WHERE ei.cluster_id = 1 AND ei.gdpp > 10000;

SELECT AVG(gdpp) AS average_gdp_per_capita
FROM economic_indicators
WHERE year = 2022 AND gdpp > 30000;

SELECT country_id, population
FROM countries
ORDER BY population DESC;

external_knowledge:
- "waves of economic tides" refers to the yearly changes in economic indicators;
- "prosperity's growth" is a metaphor for the GDP growth rate, indicating the rate at which the economy grows;
- "wealth shared by the populace" symbolizes the income per capita, reflecting the average income per person;
- "shadows of unemployment" metaphorically refers to the unemployment rate, indicating the percentage of the labor force without jobs.
